export type LinkType = "internal" | "external" | "file";

export type ButtonType = "button" | "submit" | "reset";

export type Size = "xs" | "sm" | "md" | "lg" | "xl";

export type MediaType = "image" | "video";

export type ColorType = "background" | "text" | "border" | "button";

export type Position = "left" | "right" | "bottom" | "top" | "center";

export type ToastType = "success" | "error" | "warning" | "info";

export type Shape = "circle" | "square";

export type Variant = "solid" | "soft" | "outline" | "flat";

export type InputType =
	| "text"
	| "email"
	| "password"
	| "number"
	| "tel"
	| "url"
	| "search"
	| "date"
	| "time";

export type Colors = BackgroundColors;

export type BackgroundColors =
	| "primary"
	| "secondary"
	| "none"
	| "white"
	| "black";

export type ButtonColors =
	| "primary"
	| "primary-outline"
	| "secondary"
	| "secondary-outline"
	| "ghost"
	| "none";
